const start = Date.now();

// Schedule a timer for 100ms
setTimeout(() => {
  const actualDelay = Date.now() - start;
  console.log(`Expected: 100ms, Actual: ${actualDelay}ms`);
}, 100);

// Block the Event Loop for 500ms
const blockStart = Date.now();
while (Date.now() - blockStart < 500) {
  // Busy wait
}

console.log('Event Loop was blocked for 500ms');

// Output:
// Event Loop was blocked for 500ms
// Expected: 100ms, Actual: ~500ms (or more!)

// The timer callback was queued at 100ms but couldn't execute
// until the Event Loop was unblocked at 500ms.
// Timers are NOT guaranteed to be precise — they specify
// the MINIMUM delay, not an exact delay.

// setTimeout: executes ONCE after delay
let timeoutId = setTimeout(() => {
  console.log('Executed once after 1 second');
}, 1000);

// Cancelling a timeout
clearTimeout(timeoutId); // Nothing happens

// setInterval: executes REPEATEDLY every delay
let count = 0;
const intervalId = setInterval(() => {
  count++;
  console.log(`Interval execution #${count}`);

  if (count >= 3) {
    clearInterval(intervalId);
    console.log('Interval cleared');
  }
}, 500);

// Important: setInterval doesn't account for callback execution time
// If the callback takes 200ms and interval is 500ms:
// Wait 500ms -> execute (200ms) -> wait 500ms from START of previous -> execute
// This can cause overlapping executions if callback takes longer than interval!

// Safer: recursive setTimeout
function safeInterval(fn, delay) {
  function wrapper() {
    fn();
    setTimeout(wrapper, delay);
  }
  setTimeout(wrapper, delay);
}
// This ensures the delay starts AFTER the callback completes

// In the browser:

document.getElementById('btn').addEventListener('click', () => {
  console.log('1 - click handler (macrotask)');

  Promise.resolve().then(() => {
    console.log('2 - microtask queued by click handler');
  });
});

document.getElementById('btn').addEventListener('click', () => {
  console.log('3 - second click handler (same macrotask?)');
});

// When user clicks the button:
// 1. Click event is queued in Macrotask Queue
// 2. Event Loop processes it (stack empty, microtasks clear)
// 3. First handler runs: logs '1 - click handler'
// 4. Second handler runs: logs '3 - second click handler'
// 5. Microtask from step 3 runs: logs '2 - microtask...'
//
// NOTE: Multiple handlers for the SAME event are in ONE macrotask!
// They run sequentially without microtask check in between.

// Node.js only
const fs = require('fs');

// setTimeout(cb, 0) - runs in 'Timers' phase
setTimeout(() => {
  console.log('1 - setTimeout (Timers phase)');
}, 0);

// setImmediate - runs in 'Check' phase (after I/O)
setImmediate(() => {
  console.log('2 - setImmediate (Check phase)');
});

// Inside an I/O callback, setImmediate ALWAYS runs before setTimeout
fs.readFile(__filename, () => {
  setTimeout(() => {
    console.log('3 - setTimeout inside I/O');
  }, 0);

  setImmediate(() => {
    console.log('4 - setImmediate inside I/O (wins over setTimeout)');
  });
});

// Outside I/O, the order is non-deterministic (depends on phase timing)
// But inside I/O: setImmediate (4) always runs before setTimeout (3)
